script:
/*
Storyline JS Trigger Demo Suite
Slide: 1.1 Intro Slide
Objects:
- Rectangle 1
- Oval 1

What this demo does:
1) Adds basic interactions:
   - Hover effects (cursor + subtle glow)
   - Click/tap effects (toggle spin / toggle follow)
2) Adds animations (single update loop):
   - Oval 1 orbits around its start position
   - Parallax reacts to pointer position
   - Optional follow behavior (click Oval 1 to toggle)
   - Optional rotation spin (click Rectangle 1 to toggle)

Notes:
- Uses one global update() loop for all motion.
- Uses pointerX()/pointerY() for mouse/touch.
*/

// --- Objects (by id) ---
const rect = object('6I2JMXP5x3N'); // Rectangle 1
const oval = object('6G3VcVMyj3S'); // Oval 1

// --- Visual affordances ---
rect.style.cursor = 'pointer';
oval.style.cursor = 'pointer';

// Hover glow helpers (CSS filters)
function setGlowOn(o) {
  o.style.filter = 'drop-shadow(0px 6px 10px rgba(0,0,0,0.25))';
}
function setGlowOff(o) {
  o.style.filter = '';
}

// --- Interactions (no extra triggers needed) ---
rect.pointerover(() => {
  rect.opacity = 90;
  setGlowOn(rect);
});
rect.pointerout(() => {
  rect.opacity = 100;
  setGlowOff(rect);
});

oval.pointerover(() => {
  oval.opacity = 90;
  setGlowOn(oval);
});
oval.pointerout(() => {
  oval.opacity = 100;
  setGlowOff(oval);
});

// Toggle states controlled by clicks
let spinRect = true;
let followOval = false;

rect.click(() => {
  spinRect = !spinRect;
  // quick feedback punch
  rect.scale = rect.scale + 3;
});

oval.click(() => {
  followOval = !followOval;
  // quick feedback punch
  oval.scale = oval.scale + 4;
});

// --- Animation setup (capture starting positions) ---
const start = {
  rect: { x: rect.x, y: rect.y, r: rect.rotation, s: rect.scale ?? 100 },
  oval: { x: oval.x, y: oval.y, r: oval.rotation, s: oval.scale ?? 100 }
};

// Motion parameters
const orbit = {
  radiusX: 70,
  radiusY: 35,
  speed: 1.2 // radians per second
};

const parallax = {
  amount: 18 // pixels
};

const ease = {
  pos: 0.12,
  rot: 0.18,
  scale: 0.20
};

let lastTime;
let t = 0;

// --- Single global loop ---
update((time) => {
  if (lastTime == null) lastTime = time;
  const dt = (time - lastTime) / 1000;
  lastTime = time;

  // Clamp dt to avoid huge jumps on tab-switch
  const cdt = Math.min(0.05, Math.max(0, dt));
  t += cdt;

  // Pointer normalized (-0.5..0.5)
  const nx = (pointerX() / slideWidth()) - 0.5;
  const ny = (pointerY() / slideHeight()) - 0.5;

  // Target positions
  // Oval: orbit + parallax or optionally follow pointer
  let targetOvalX;
  let targetOvalY;

  if (followOval) {
    targetOvalX = pointerX() - oval.width / 2;
    targetOvalY = pointerY() - oval.height / 2;
  } else {
    const ox = Math.cos(t * orbit.speed * Math.PI * 2) * orbit.radiusX;
    const oy = Math.sin(t * orbit.speed * Math.PI * 2) * orbit.radiusY;

    targetOvalX = start.oval.x + ox + nx * parallax.amount;
    targetOvalY = start.oval.y + oy + ny * parallax.amount;
  }

  // Rectangle: subtle parallax only
  const targetRectX = start.rect.x + nx * (parallax.amount * 0.6);
  const targetRectY = start.rect.y + ny * (parallax.amount * 0.6);

  // Target rotations
  const targetRectRot = spinRect ? (rect.rotation + 120 * cdt) : start.rect.r;
  const targetOvalRot = followOval ? (oval.rotation + 180 * cdt) : (Math.sin(t * 2.2) * 8);

  // Ease positions
  oval.x += (targetOvalX - oval.x) * ease.pos;
  oval.y += (targetOvalY - oval.y) * ease.pos;

  rect.x += (targetRectX - rect.x) * ease.pos;
  rect.y += (targetRectY - rect.y) * ease.pos;

  // Ease rotations
  rect.rotation += (targetRectRot - rect.rotation) * ease.rot;
  oval.rotation += (targetOvalRot - oval.rotation) * ease.rot;

  // Ease scales back to normal after click “punch”
  const rectTargetScale = 100;
  const ovalTargetScale = 100;
  rect.scale += (rectTargetScale - rect.scale) * ease.scale;
  oval.scale += (ovalTargetScale - oval.scale) * ease.scale;
});

const  = object('ObjectID');
addToTimeline(
  objectName.animate(
    [
      { transform: 'translateX(0px)' },
      { transform: 'translateX(200px) rotate(45deg)', filter: 'blur(4px)' }
    ],
    {
      duration: 1000, // Animation duration in milliseconds<
      easing: 'ease-in-out', // Easing function
      fill: 'forwards' // Keep the final state after animation
    }
  )
);
